// Get grid list
protected override async Task HandleValidatedRequestAsync(PagedRequest req, CancellationToken ct)
{
    var parameters = new ActionQueryParameters()
        .WithSearch(req.Search)
        .WithStatus(req.Status)
        .WithPagination(skip: (req.Page - 1) * req.PageSize, take: req.PageSize);

    var dataTask = getActionsQuery.ExecuteAsync(parameters, ct);
    var countTask = getActionsCountQuery.ExecuteAsync(parameters, ct);
    await Task.WhenAll(dataTask, countTask);

    var items = actionDTOMapper.MapGridItem(
        (await dataTask).ToList(), RequestLanguageId, DefaultLanguageId);
    await Send.OkAsync(
        new GridListResponse<ActionGridItemDTO>(items, await countTask, req.Page, req.PageSize), ct);
}

