public class WorkflowDTOMapper(TranslationService translationService)
{
    public WorkflowDTO Map(
        Workflow entity,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        IList<TriggerType> triggerTypes)
    {
        var translation = translationService.GetEntityTranslation(
            entity, requestLanguageId, defaultLanguageId);

        var triggers = entity.Triggers
            .Select(t => triggerTypes.FirstOrDefault(tt => tt.Id == t.TriggerTypeId))
            .Where(tt => tt is not null)
            .Select(tt => new NamedDTO
            {
                Id = tt!.Id,
                Name = tt.Code,
                Description = tt.DisplayName,
            })
            .ToList();

        return new WorkflowDTO
        {
            Id = entity.Id,
            Name = translation.Name,
            Description = translation.Description,
            Triggers = triggers,
            StepCount = entity.Steps.Count,
            CreatedDate = entity.CreatedDate,
        };
    }

    public IList<WorkflowDTO> Map(
        IList<Workflow> entities,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        IList<TriggerType> triggerTypes)
    {
        return entities
            .Select(e => Map(e, requestLanguageId, defaultLanguageId, triggerTypes))
            .ToList();
    }
}

