// Features/ComplianceProfiles/Shared/Mappers/ComplianceProfileDTOMapper.cs

public class ComplianceProfileDTOMapper(TranslationService translationService)
{
    public ComplianceProfileDTO Map(
        ComplianceProfile entity,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        ComplianceProfileDTOMapperDataContext context)
    {
        var translation = translationService.GetEntityTranslation(
            entity, requestLanguageId, defaultLanguageId);

        return new ComplianceProfileDTO
        {
            Id = entity.Id,
            Name = translation.Name,
            Description = translation.Description,
            Actions = entity.ProfileActions
                .Where(pa => context.ActionMap.ContainsKey(pa.ActionId))
                .Select(pa => new NamedDTO
                {
                    Id = pa.ActionId,
                    Name = context.ActionMap[pa.ActionId].Name,
                })
                .ToList(),
            RequiredApprovals = context.RequiredApprovals,
        };
    }

    public IList<ComplianceProfileDTO> Map(
        IList<ComplianceProfile> entities,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        ComplianceProfileDTOMapperDataContext context)
    {
        return entities
            .Select(e => Map(e, requestLanguageId, defaultLanguageId, context))
            .ToList();
    }
}

